  toolText: { color: '#E5E7EB', fontSize: 12 },
  toolTextActive: { color: '#EFF6FF', fontWeight: '600' },
  primarySmall: {
    borderRadius: 999,
    backgroundColor: '#111827',
    paddingVertical: 8,
    paddingHorizontal: 14,
    justifyContent: 'center',
    alignItems: 'center',
  },
  primarySmallText: { color: '#FFFFFF', fontSize: 12, fontWeight: '600' },
  secondarySmall: {
    flex: 1,
    borderRadius: 999,
    borderWidth: 1,
    borderColor: '#334155',
    paddingVertical: 8,
    paddingHorizontal: 14,
    justifyContent: 'center',
    alignItems: 'center',
  },
  secondarySmallText: { color: '#E5E7EB', fontSize: 12, fontWeight: '600' },
  inputRow: {
    flexDirection: 'row',
    alignItems: 'center',
    padding: 12,
    borderTopWidth: 1,
    borderTopColor: '#E5E7EB',
    backgroundColor: '#FFFFFF',
  },
  input: {
    flex: 1,
    borderRadius: 999,
    borderWidth: 1,
    borderColor: '#E5E7EB',
    paddingHorizontal: 12,
    paddingVertical: 10,
    fontSize: 13,
    color: '#111827',
    marginRight: 8,
  },
  sendBtn: {
    borderRadius: 999,
